import React from 'react';

const Construction = () => {
    return (
        <div className="container text-center py-5 my-5">
            <h1 className="display-4 text-primary">Page en construction</h1>
            <p className="lead">Cette page sera prochainement remplie par un cabinet spécialisé.</p>
            <hr className="my-4" style={{ width: '50px', margin: 'auto' }} />
        </div>
    );
};

export default Construction;
